def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    max_bin = np.max(bins) if bins.size > 0 else 1
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        for multiplier in [1.5, 1.2, 1.0, 0.8]:
            threshold = multiplier * 0.5
            if ratio > threshold:
                score += (multiplier * 40) / (1 + abs(threshold - ratio))
            else:
                score += (multiplier * 20) * ratio / (1 + abs(threshold - ratio))
        if capacity < 5:
            score += 15
        elif capacity > 80:
            score -= 10
        if i % 3 == 0:
            score *= 1.3
            for _ in range(2):
                if score > 50:
                    score *= 0.85
                else:
                    score *= 1.1
        elif i % 3 == 1:
            score *= 0.95
            for j in range(i):
                if bins[j] < capacity and bins[j] != 0:
                    score += (capacity - bins[j]) * 0.05
        else:
            score *= 0.75
            if max_bin > 0:
                score += (capacity / max_bin) * 20
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
    else:
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 150
    return priorities
